import React, { useEffect, useState } from "react";
import axios from "axios";

const getStatusColor = (status) => {
  switch (status) {
    case "Healthy":
      return "green";
    case "Degraded":
      return "orange";
    case "Down":
      return "red";
    default:
      return "gray";
  }
};

function App() {
  const [apis, setApis] = useState([]);

  useEffect(() => {
    const fetchStatus = async () => {
      const res = await axios.get("http://localhost:5000/api/status");
      setApis(res.data);
    };
    fetchStatus();
  }, []);

  const retryAPI = async (url) => {
    try {
      const res = await axios.get("http://localhost:5000/api/retry", {
        params: { url },
      });

      // Replace the old result with the new one
      setApis((prevStatuses) =>
        prevStatuses.map((api) => (api.url === url ? res.data : api))
      );
    } catch (err) {
      console.error("Retry failed for:", url);
    }
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h1>API Connectivity Dashboard</h1>
      <table border="1" cellPadding="8">
        <thead>
          <tr>
            <th>API Name</th>
            <th>Status</th>
            <th>Response Time</th>
            <th>Last Error</th>
          </tr>
        </thead>
        <tbody>
          {apis.map((api, index) => (
            <tr key={index}>
              <td>{api.apiName}</td>
              <td style={{ color: getStatusColor(api.status) }}>
                {api.status}
              </td>
              <td>{api.responseTime ? `${api.responseTime} ms` : "—"}</td>
              <td>{api.lastError || "—"}</td>
              <td>
                {api.status !== "Healthy" && (
                  <button onClick={() => retryAPI(api.url)}>Retry</button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;
